decimal OpenMachineReport  = 0;
decimal groupSumOpenEggs  =0;
decimal CloseMachineReport  = 0;
decimal groupSumCloseEggs  = 0 ;
decimal OpenEggsReport  = 0 ;
decimal openEggStoreEggsReport  = 0;
decimal recEggsReport  = 0;
decimal groupSumOpenBalance = 0 ;
decimal TotalEggsAndChicksReport  = 0 ;
decimal groupSumEggsAndChicks  = 0 ;
decimal openSetterEggsGroup  = 0;
decimal openHatcherEggsGroup  = 0;
decimal closeSetterEggsReport  = 0;
decimal closeHatcherEggsReport = 0;
decimal deadsGroup = 0;
decimal cullsGroup = 0;
decimal destroyedEggsGroup = 0;
