decimal chicksGroup = 0;
private void xrTableCell31_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare values ---
decimal openSetterEggs = 0;
decimal openHatcherEggs = 0;

// --- OpenSetterEggs ---
if (GetCurrentColumnValue("OpenSetterEggs") != null)
    openSetterEggs = Convert.ToDecimal(GetCurrentColumnValue("OpenSetterEggs"));

// --- OpenHatcherEggs ---
if (GetCurrentColumnValue("OpenHatcherEggs") != null)
    openHatcherEggs = Convert.ToDecimal(GetCurrentColumnValue("OpenHatcherEggs"));

// --- Result (sum) ---
decimal result = openSetterEggs + openHatcherEggs;
XRTableCell cell = sender as XRTableCell;
cell.Text = result.ToString("N0"); // no decimals, adjust format if needed
openSetterEggsReport += openSetterEggs ;
openHatcherEggsReport += openHatcherEggs ;
OpenMachineReport = openSetterEggsReport + openHatcherEggsReport ;

}

private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare values ---
decimal openSetterEggs = 0;
decimal openHatcherEggs = 0;

// --- OpenSetterEggs ---
if (GetCurrentColumnValue("OpenSetterEggs") != null)
    openSetterEggs = Convert.ToDecimal(GetCurrentColumnValue("OpenSetterEggs"));

// --- OpenHatcherEggs ---
if (GetCurrentColumnValue("OpenHatcherEggs") != null)
    openHatcherEggs = Convert.ToDecimal(GetCurrentColumnValue("OpenHatcherEggs"));

// --- Add to group sum ---
openSetterEggsGroup +=  openSetterEggs ;  
openHatcherEggsGroup += openHatcherEggs ;
groupSumOpenEggs = (openSetterEggsGroup + openHatcherEggsGroup );
    // --- Declare values ---
decimal closeSetterEggs = 0;
decimal closeHatcherEggs = 0;

// --- OpenSetterEggs ---
if (GetCurrentColumnValue("CloseSetterEggs") != null)
    closeSetterEggs = Convert.ToDecimal(GetCurrentColumnValue("CloseSetterEggs"));

// --- OpenHatcherEggs ---
if (GetCurrentColumnValue("CloseHatcherEggs") != null)
    closeHatcherEggs = Convert.ToDecimal(GetCurrentColumnValue("CloseHatcherEggs"));

// --- Add to group sum ---
closeSetterEggsReport += closeSetterEggs ;
closeHatcherEggsReport += closeHatcherEggs;
groupSumCloseEggs += (closeSetterEggs + closeHatcherEggs);
// --- Declare values ---
decimal openEggStoreEggs = 0;
decimal recEggs = 0;

// --- OpenEggStoreEggs ---
if (GetCurrentColumnValue("OpenEggStoreEggs") != null)
    openEggStoreEggs = Convert.ToDecimal(GetCurrentColumnValue("OpenEggStoreEggs"));

// --- RecEggs ---
if (GetCurrentColumnValue("RecEggs") != null)
    recEggs = Convert.ToDecimal(GetCurrentColumnValue("RecEggs"));

// --- Add to group sum ---
openEggStoreEggsReport += openEggStoreEggs ;
recEggsReport += recEggs  ;
groupSumOpenBalance = (openEggStoreEggsReport + recEggsReport );

// --- Declare values ---
decimal deads = 0;
decimal culls = 0;
decimal destroyedEggs = 0;
decimal unHatEggs = 0;
decimal chicks = 0;

// --- Deads ---
if (GetCurrentColumnValue("Deads") != null)
    deads = Convert.ToDecimal(GetCurrentColumnValue("Deads"));

// --- Culls ---
if (GetCurrentColumnValue("Culls") != null)
    culls = Convert.ToDecimal(GetCurrentColumnValue("Culls"));

// --- DestroyedEggs ---
if (GetCurrentColumnValue("DestroyedEggs") != null)
    destroyedEggs = Convert.ToDecimal(GetCurrentColumnValue("DestroyedEggs"));

// --- UnHatEggs ---
if (GetCurrentColumnValue("UnHatEggs") != null)
    unHatEggs = Convert.ToDecimal(GetCurrentColumnValue("UnHatEggs"));

// --- Chicks ---
if (GetCurrentColumnValue("Chicks") != null)
    chicks = Convert.ToDecimal(GetCurrentColumnValue("Chicks"));

// --- Add to group sum ---
deadsGroup += deads;
cullsGroup += culls;
destroyedEggsGroup += destroyedEggs;
unHatEggsGroup += unHatEggs;
chicksGroup += chicks;

groupSumEggsAndChicks += (deadsGroup + cullsGroup + destroyedEggsGroup + unHatEggsGroup + chicksGroup );


}

private void xrTableCell77_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
          xrTableCell77.Text = groupSumOpenEggs.ToString("N0");

}

