private void xrTableCell49_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare values ---
decimal deads = 0;
decimal culls = 0;
decimal destroyedEggs = 0;
decimal unHatEggs = 0;
decimal chicks = 0;
decimal deadsTotalReport = 0;
decimal cullsTotalReport = 0;
decimal destroyedEggsTotalReport = 0;
decimal unHatEggsTotalReport = 0;
decimal chicksTotalReport = 0;

// --- Deads ---
if (GetCurrentColumnValue("Deads") != null)
    deads = Convert.ToDecimal(GetCurrentColumnValue("Deads"));

// --- Culls ---
if (GetCurrentColumnValue("Culls") != null)
    culls = Convert.ToDecimal(GetCurrentColumnValue("Culls"));

// --- DestroyedEggs ---
if (GetCurrentColumnValue("DestroyedEggs") != null)
    destroyedEggs = Convert.ToDecimal(GetCurrentColumnValue("DestroyedEggs"));

// --- UnHatEggs ---
if (GetCurrentColumnValue("UnHatEggs") != null)
    unHatEggs = Convert.ToDecimal(GetCurrentColumnValue("UnHatEggs"));

// --- Chicks ---
if (GetCurrentColumnValue("Chicks") != null)
    chicks = Convert.ToDecimal(GetCurrentColumnValue("Chicks"));

// --- Result (sum) ---
decimal result = deads + culls + destroyedEggs + unHatEggs + chicks;

// --- Assign result to the cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = result.ToString("0"); // no decimals, adjust format if needed
deadsTotalReport += deads;
cullsTotalReport += culls;
destroyedEggsTotalReport += destroyedEggs;
unHatEggsTotalReport += unHatEggs;
chicksTotalReport += chicks;
TotalEggsAndChicksReport = deadsTotalReport  + cullsTotalReport  + destroyedEggsTotalReport  + unHatEggsTotalReport  + chicksTotalReport ;


}

